package com.infy.inventrack.catalog.entity; import jakarta.persistence.*; import lombok.*; import java.math.BigDecimal; @Getter @Setter @NoArgsConstructor @Entity @Table(name="products") public class Product { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Integer productId; @Column(nullable=false,length=100) private String productName; @Column(nullable=false,unique=true,length=20) private String sku; @Column(nullable=false,precision=12,scale=2) private BigDecimal price; @Column(nullable=false) private String imageUrl; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="category_id",nullable=false) private Category category; @Column(length=500) private String description; @Column(nullable=false,length=50) private String brand; @Column(nullable=false) private Integer stockQuantity; }
